  "home.featured.subtitle": { tr: "Koleksiyonlarımızdan özenle seçtiğimiz imza tasarımlar.", en: "Signature designs carefully chosen from our collections.", ar: "تصاميم مميّزة اخترناها بعناية من مجموعاتنا.", ru: "Знаковые модели, тщательно отобранные из наших коллекций." },
  "home.featured.cta": { tr: "Tüm Gelinlikler", en: "View All Gowns", ar: "جميع الفساتين", ru: "Все платья" },
