  "header.logoHomeLabel": { tr: "Celine Gelinlik ana sayfa", en: "Celine Gelinlik home page", ar: "الصفحة الرئيسية لـ Celine Gelinlik", ru: "Celine Gelinlik — главная страница" },
  "cta.eyebrow": { tr: "Randevu", en: "Appointment", ar: "حجز موعد", ru: "Запись на приём" },
  "cta.title": { tr: "Size özel bir gelinlik yolculuğu", en: "A bridal journey made just for you", ar: "رحلة زفاف مصمّمة خصيصاً لكِ", ru: "Свадебное путешествие, созданное только для вас" },
  "cta.text": { tr: "Atölyemizde birebir görüşme için randevu oluşturun; hikâyenizi dinleyelim, ölçüye özel tasarımınıza birlikte başlayalım.", en: "Book a private consultation at our atelier; let us hear your story and begin your made-to-measure design together.", ar: "احجزي موعداً للقاء خاص في أتيليهنا؛ لنستمع إلى قصتكِ ونبدأ معاً تصميم فستانكِ المُفصّل على مقاسكِ.", ru: "Запишитесь на индивидуальную встречу в нашем ателье; мы выслушаем вашу историю и вместе начнём создавать платье по вашим меркам." },
  "cta.whatsappText": { tr: "Merhaba, Celine Gelinlik için randevu almak istiyorum.", en: "Hello, I would like to book an appointment at Celine Gelinlik.", ar: "مرحباً، أودّ حجز موعد لدى Celine Gelinlik.", ru: "Здравствуйте, я хотела бы записаться на приём в Celine Gelinlik." },
