  "form.phone.error.invalid": { tr: "Geçerli bir cep telefonu girin (örn. 05XX XXX XX XX).", en: "Please enter a valid mobile number (e.g. 05XX XXX XX XX).", ar: "يُرجى إدخال رقم هاتف محمول صحيح (مثال: 05XX XXX XX XX).", ru: "Введите корректный номер мобильного телефона (напр. 05XX XXX XX XX)." },
